  }

  function clearAndResetForm() {
    activeId = null;
    if (noteTitle) noteTitle.value = '';
    if (noteContent) noteContent.value = '';
  }

  function fetchNotes() {
    // No API key / Content-Type on GET
    return fetch(API_BASE).then((r) => {
      if (!r.ok) throw new Error('Failed to load notes');
      return r.json();
    });
  }

  function apiRequest(method, url, bodyObj) {
    return getApiKey().then((key) => {
      const headers = {
        'Content-Type': 'application/json',
        'x-api-key': key
      };
      const opts = { method, headers };
      if (bodyObj !== undefined) opts.body = JSON.stringify(bodyObj);
      return fetch(url, opts).then((r) => {
        if (!r.ok) throw new Error(method + ' failed');
        // API may or may not return JSON; don't assume
        return r.text().then(() => r);
      });
    });
  }

  function renderNotes(notes) {
    if (!notesList) return;

    // Clear list
    while (notesList.firstChild) notesList.removeChild(notesList.firstChild);

    for (let i = 0; i < notes.length; i++) {
      const n = notes[i];

      const row = document.createElement('div');
      row.className = 'note-row';
      row.setAttribute('data-id', String(n.id));

      const titleEl = document.createElement('span');
      titleEl.className = 'note-title';
      titleEl.textContent = n.title;

      const contentEl = document.createElement('span');
      contentEl.className = 'note-content';
      contentEl.textContent = n.content;

      const editBtn = document.createElement('button');
      editBtn.type = 'button';
      editBtn.className = 'edit-btn';
      editBtn.textContent = 'Edit';
      editBtn.addEventListener('click', () => {
        activeId = n.id;
        if (noteTitle) noteTitle.value = n.title || '';
        if (noteContent) noteContent.value = n.content || '';
      });

      const deleteBtn = document.createElement('button');
      deleteBtn.type = 'button';
      deleteBtn.className = 'delete-btn';
      deleteBtn.textContent = 'Delete';
      deleteBtn.addEventListener('click', () => {
        apiRequest('DELETE', API_BASE + '/' + encodeURIComponent(String(n.id)))
          .then(() => loadNotes())
          .then(() => {
            if (activeId === n.id) clearAndResetForm();
          })
          .catch(() => {});
      });

      row.appendChild(titleEl);
      row.appendChild(document.createTextNode(' '));
      row.appendChild(contentEl);
      row.appendChild(document.createTextNode(' '));
      row.appendChild(editBtn);
      row.appendChild(document.createTextNode(' '));
      row.appendChild(deleteBtn);

      notesList.appendChild(row);
    }
  }

  function loadNotes() {
    return fetchNotes().then((notes) => {
      renderNotes(Array.isArray(notes) ? notes : []);
      return notes;
    });
  }

  if (noteForm) {
    noteForm.addEventListener('submit', (e) => {
      if (e && e.preventDefault) e.preventDefault();

      const title = (noteTitle && noteTitle.value ? noteTitle.value : '').trim();
      const content = (noteContent && noteContent.value ? noteContent.value : '').trim();

      if (!title && !content) {
        // nothing to save
        return;
      }

      if (activeId == null) {
        apiRequest('POST', API_BASE, { title, content })
          .then(() => {
            clearAndResetForm();
            return loadNotes();
          })
