      } else {
        apiRequest('PUT', API_BASE + '/' + encodeURIComponent(String(activeId)), { title, content })
          .then(() => {
            clearAndResetForm();
            return loadNotes();
          })
          .catch(() => {});
      }
    });
  }

  // Initial load
  loadNotes().catch(() => {});
})();
